VALUES
  ('aviation-6c581c7e-moex-00094', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '人民為開設餐廳而向地方政府經濟發展局申請商業登記，惟主管機關以負責人仍欠繳交通違規罰鍰為 由，拒絕當事人申請。此舉應屬違反下列何者？', '["比例原則", "誠實信用原則", "明確性原則", "不當聯結禁止原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00095', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '有關大學自治，下列敘述何者錯誤？', '["大學於教學研究相關之範圍內，就其內部組織應享有相當程度之自主組織權", "大學得自行制定章則，對成績未達一定標準之學生予以退學處分", "大學對學生所為處分若未剝奪其學生身分，行政法院必須尊重大學自治而不應受理救濟", "大學就入學資格條件所訂定之自治規章，在不違背自治權範圍內，不生違反法律保留原則之問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00096', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '給付不能乃債務不履行類型之一。關於給付不能，下列敘述何者錯誤？', '["因不可歸責於債務人之事由，致給付不能者，債務人免給付義務", "因可歸責於債務人之事由，致給付不能者，債權人得請求賠償損害", "因可歸責於債務人之事由，致給付一部不能者，若其他部分之履行，於債權人無利益時，債權人僅 得請求一部不履行之損害賠償", "債務人因給付不能之事由，對第三人有損害賠償請求權者，債權人得向債務人請求讓與其損害賠償 請求權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00097', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依民法之規定，管理人明知為他人之事務，而為自己之利益管理之者，稱為：', '["不法管理", "誤信管理", "幻想管理", "表見代理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00098', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '警察逮捕張三後，將張三移送至警察局拘禁張三，未有任何處置。4天後，張三趁警察不注意，以拾 得的迴紋針打開手銬及門鎖，逃之夭夭。依據實務見解，下列敘述何者正確？', '["張三的行為構成刑法第161條脫逃罪，因為張三係為警察所逮捕，以不法方式脫離公權力拘禁", "張三的行為構成刑法第161條脫逃罪，因為張三係受拘禁之人，以不法方式脫離公權力拘禁", "張三的行為不構成刑法第161條脫逃罪，因為張三未使用強暴或脅迫的方法", "張三的行為不構成刑法第161條脫逃罪，因為張三並非依法逮捕、拘禁之人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00099', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '有關「緩刑」之敘述，下列何者正確？', '["緩刑之效力及於從刑、保安處分及沒收之宣告", "縱為緩刑宣告，亦不得命犯罪行為人向被害人道歉", "受2年以下有期徒刑、拘役或罰金之宣告，曾因過失犯罪受有期徒刑以上刑之宣告者，不得宣告緩刑", "緩刑期間自裁判確定之日起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00100', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '衛生局官員張三對於李四的餐廳實施衛生檢查時，指出若干不合標準之處。李四不服，便罵道：「你 有什麼了不起，不就是一隻納稅人養的米蟲」等等侮辱的詞句。下列敘述何者正確？', '["李四的行為，不構成犯罪", "李四的行為，構成了刑法第140條第2項侮辱公署罪，因侮辱了衛生局官員", "李四的行為，構成了刑法第140條第1項侮辱公務員罪，因其對於正依法執行職務之公務員，當場侮辱", "李四的行為，構成了刑法第140條第1項侮辱公務員罪，因其侮辱了張三所執行的職務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00101', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '有關著作人格權的敘述，下列何者錯誤？', '["甲為某音樂著作之著作人，若乙未經甲同意擅自將該著作公諸於世，侵害甲的公開發表權", "丙為某語文著作之著作人，丙有決定是否表示於該著作之重製物上表示自己姓名之權利", "丁為某美術著作之著作人，若戊違反丁的意願擅自改變丁的著作之內容，即使無損於丁的名譽，亦 侵害丁之著作人格權", "己為某語文著作之著作人，若他人將該語文著作改作為視聽著作，則己得要求於該視聽著作公開發 表時，表示其姓名"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00102', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依據行政罰法第5條規定，行為後法律若有變更，原則上適用最初裁處時之法律，但裁處前之法律有 利於受處罰者時，應適用最有利於受處罰者之規定。以上之敘述係下列何一原則之例外？', '["信賴保護原則", "罪疑惟輕原則", "特別法優於普通法原則", "後法優於前法原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00103', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '下列何者得為遺囑見證人？', '["已結婚之未成年人", "受輔助宣告人", "受遺贈人之旁系血親", "公證人之助理人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL)
